import java.util.HashMap;
import java.util.Map;

public class Main {
    public static void main(String[] args) {
        HashMap<String, Integer> ages = new HashMap<>();
        ages.put("Ali", 25);
        ages.put("Veli", 30);
        ages.put("Ayse", 28);

        System.out.println("Tum kayitlar:");
        for (Map.Entry<String, Integer> entry : ages.entrySet()) {
            System.out.println(entry.getKey() + " -> " + entry.getValue() + " yasinda");
        }

        // Anahtar kontrolu
        if (ages.containsKey("Ali")) {
            System.out.println("\nAli'nin yasi: " + ages.get("Ali"));
        }

        // Guncelleme
        ages.put("Ali", 26);
        System.out.println("Ali'nin yeni yasi: " + ages.get("Ali"));

        // Silme
        ages.remove("Veli");
        System.out.println("\nVeli silindikten sonra kayit sayisi: " + ages.size());

        // getOrDefault
        int zeynepAge = ages.getOrDefault("Zeynep", -1);
        System.out.println("\nZeynep'in yasi (yoksa -1): " + zeynepAge);
    }
}
